import React from "react";
import { motion } from "framer-motion";
import Button from "../components/Button"; // ✅ Ensure this exists in the components folder

function Home() {
  return (
    <div className="bg-gray-100 min-h-screen flex flex-col items-center">
      {/* Hero Section */}
      <header className="text-center py-16 bg-white w-full">
        <h1 className="text-4xl font-bold text-black">Welcome to Ink N Threadworks</h1>
        <p className="text-gray-700 mt-2 text-lg">Custom screen printing and embroidery made simple.</p>
        <motion.div whileHover={{ scale: 1.05 }} className="mt-6">
          <Button className="bg-gray-700 text-white px-6 py-3 rounded-lg">
            Start Designing
          </Button>
        </motion.div>
      </header>

      {/* Features Section */}
      <section className="p-8 text-center">
        <h2 className="text-2xl font-semibold text-black">Why Choose Us?</h2>
        <div className="flex flex-wrap justify-center mt-6 gap-6">
          <div className="bg-white p-6 rounded-lg shadow-md max-w-sm">
            <h3 className="text-xl font-bold text-gray-900">High-Quality Prints</h3>
            <p className="text-gray-600 mt-2">We use industry-leading techniques to ensure the best print quality.</p>
          </div>
          <div className="bg-white p-6 rounded-lg shadow-md max-w-sm">
            <h3 className="text-xl font-bold text-gray-900">Custom Embroidery</h3>
            <p className="text-gray-600 mt-2">Personalized embroidery for professional and personal needs.</p>
          </div>
          <div className="bg-white p-6 rounded-lg shadow-md max-w-sm">
            <h3 className="text-xl font-bold text-gray-900">Fast Turnaround</h3>
            <p className="text-gray-600 mt-2">Get your orders completed quickly without sacrificing quality.</p>
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="p-8 text-center bg-gray-200 w-full">
        <h2 className="text-2xl font-semibold text-black">Ready to Get Started?</h2>
        <p className="text-gray-700 mt-2">Start designing your custom apparel today.</p>
        <motion.div whileHover={{ scale: 1.05 }} className="mt-6">
          <Button className="bg-gray-700 text-white px-6 py-3 rounded-lg">
            Start Designing
          </Button>
        </motion.div>
      </section>
    </div>
  );
}

export default Home;
